from __future__ import annotations

from dataclasses import dataclass, field
import json
from pathlib import Path
from typing import Any, Dict, List, Mapping, Optional

from src.trader.execution.opportunity_candidate import (
    OpportunityCandidate,
    OpportunityCandidateError,
    normalize_opportunity_candidate,
)


class OpportunityCandidateStoreError(RuntimeError):
    """Raised when opportunity-candidate store inputs or rows are invalid."""


def _require_non_empty_string(name: str, value: Any) -> str:
    if not isinstance(value, str) or not value.strip():
        raise OpportunityCandidateStoreError(f"{name} must be a non-empty string")
    return value.strip()


def _normalize_path(path: Any) -> Path:
    if isinstance(path, Path):
        return path
    if not isinstance(path, str) or not path.strip():
        raise OpportunityCandidateStoreError("store_path must be a non-empty string or Path")
    return Path(path)


def _normalize_metadata(value: Any) -> Dict[str, Any]:
    if value is None:
        return {}
    if not isinstance(value, Mapping):
        raise OpportunityCandidateStoreError("metadata must be a mapping when provided")
    return dict(value)


@dataclass(frozen=True)
class OpportunityCandidateStoreRecord:
    opportunity_candidate_id: str
    scanner_run_id: str
    appended_at_utc: str
    candidate: OpportunityCandidate
    metadata: Dict[str, Any] = field(default_factory=dict)

    def __post_init__(self) -> None:
        opportunity_candidate_id = _require_non_empty_string(
            "opportunity_candidate_id",
            self.opportunity_candidate_id,
        )
        scanner_run_id = _require_non_empty_string("scanner_run_id", self.scanner_run_id)
        appended_at_utc = _require_non_empty_string("appended_at_utc", self.appended_at_utc)
        candidate = (
            self.candidate
            if isinstance(self.candidate, OpportunityCandidate)
            else normalize_opportunity_candidate(self.candidate)
        )
        metadata = _normalize_metadata(self.metadata)

        if opportunity_candidate_id != candidate.opportunity_candidate_id:
            raise OpportunityCandidateStoreError(
                "opportunity_candidate_id must match candidate.opportunity_candidate_id"
            )
        if scanner_run_id != candidate.lineage.scanner_run_id:
            raise OpportunityCandidateStoreError(
                "scanner_run_id must match candidate.lineage.scanner_run_id"
            )

        object.__setattr__(self, "opportunity_candidate_id", opportunity_candidate_id)
        object.__setattr__(self, "scanner_run_id", scanner_run_id)
        object.__setattr__(self, "appended_at_utc", appended_at_utc)
        object.__setattr__(self, "candidate", candidate)
        object.__setattr__(self, "metadata", metadata)

    def to_dict(self) -> Dict[str, Any]:
        return {
            "opportunity_candidate_id": self.opportunity_candidate_id,
            "scanner_run_id": self.scanner_run_id,
            "appended_at_utc": self.appended_at_utc,
            "candidate": self.candidate.to_dict(),
            "metadata": dict(self.metadata),
        }

    @classmethod
    def from_dict(cls, payload: Mapping[str, Any]) -> "OpportunityCandidateStoreRecord":
        if not isinstance(payload, Mapping):
            raise OpportunityCandidateStoreError("payload must be a mapping")
        return cls(
            opportunity_candidate_id=payload.get("opportunity_candidate_id"),
            scanner_run_id=payload.get("scanner_run_id"),
            appended_at_utc=payload.get("appended_at_utc"),
            candidate=payload.get("candidate"),
            metadata=dict(payload.get("metadata") or {}),
        )


@dataclass(frozen=True)
class OpportunityCandidateStoreScan:
    store_path: str
    row_count: int
    valid_row_count: int
    invalid_row_count: int
    latest_opportunity_candidate_id: Optional[str]
    latest_scanner_run_id: Optional[str]
    issues: List[str] = field(default_factory=list)

    def to_dict(self) -> Dict[str, Any]:
        return {
            "store_path": self.store_path,
            "row_count": self.row_count,
            "valid_row_count": self.valid_row_count,
            "invalid_row_count": self.invalid_row_count,
            "latest_opportunity_candidate_id": self.latest_opportunity_candidate_id,
            "latest_scanner_run_id": self.latest_scanner_run_id,
            "issues": list(self.issues),
        }


def _ensure_parent_directory(path: Path) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)


def append_opportunity_candidate_record(
    *,
    store_path: Any,
    candidate: Any,
    appended_at_utc: Any,
    metadata: Optional[Mapping[str, Any]] = None,
) -> OpportunityCandidateStoreRecord:
    normalized_path = _normalize_path(store_path)
    normalized_candidate = normalize_opportunity_candidate(candidate)
    normalized_appended_at_utc = _require_non_empty_string("appended_at_utc", appended_at_utc)
    normalized_metadata = dict(metadata or {})

    record = OpportunityCandidateStoreRecord(
        opportunity_candidate_id=normalized_candidate.opportunity_candidate_id,
        scanner_run_id=normalized_candidate.lineage.scanner_run_id,
        appended_at_utc=normalized_appended_at_utc,
        candidate=normalized_candidate,
        metadata=normalized_metadata,
    )

    _ensure_parent_directory(normalized_path)
    with normalized_path.open("a", encoding="utf-8", newline="") as handle:
        handle.write(json.dumps(record.to_dict(), sort_keys=True))
        handle.write("\n")

    return record


def read_opportunity_candidate_records(
    *,
    store_path: Any,
    strict: bool = True,
) -> List[OpportunityCandidateStoreRecord]:
    normalized_path = _normalize_path(store_path)
    if not normalized_path.exists():
        return []

    records: List[OpportunityCandidateStoreRecord] = []
    with normalized_path.open("r", encoding="utf-8") as handle:
        for line_number, raw_line in enumerate(handle, start=1):
            line = raw_line.strip()
            if not line:
                continue

            try:
                payload = json.loads(line)
            except json.JSONDecodeError as exc:
                if strict:
                    raise OpportunityCandidateStoreError(
                        f"malformed JSON row at line {line_number}"
                    ) from exc
                continue

            try:
                records.append(OpportunityCandidateStoreRecord.from_dict(payload))
            except (OpportunityCandidateStoreError, OpportunityCandidateError) as exc:
                if strict:
                    raise OpportunityCandidateStoreError(
                        f"malformed opportunity candidate row at line {line_number}"
                    ) from exc
                continue

    return records


def get_latest_opportunity_candidate_record(
    *,
    store_path: Any,
    strict: bool = True,
) -> Optional[OpportunityCandidateStoreRecord]:
    records = read_opportunity_candidate_records(store_path=store_path, strict=strict)
    if not records:
        return None
    return records[-1]


def replay_opportunity_candidate_by_id(
    *,
    store_path: Any,
    opportunity_candidate_id: Any,
    strict: bool = True,
) -> OpportunityCandidateStoreRecord:
    normalized_id = _require_non_empty_string(
        "opportunity_candidate_id",
        opportunity_candidate_id,
    )
    records = read_opportunity_candidate_records(store_path=store_path, strict=strict)
    for record in records:
        if record.opportunity_candidate_id == normalized_id:
            return record
    raise OpportunityCandidateStoreError(
        f"opportunity candidate not found: {normalized_id}"
    )


def replay_opportunity_candidates_by_scanner_run(
    *,
    store_path: Any,
    scanner_run_id: Any,
    strict: bool = True,
) -> List[OpportunityCandidateStoreRecord]:
    normalized_scanner_run_id = _require_non_empty_string("scanner_run_id", scanner_run_id)
    records = read_opportunity_candidate_records(store_path=store_path, strict=strict)
    return [
        record
        for record in records
        if record.scanner_run_id == normalized_scanner_run_id
    ]


def index_latest_opportunity_candidates_by_id(
    *,
    store_path: Any,
    strict: bool = True,
) -> Dict[str, OpportunityCandidateStoreRecord]:
    records = read_opportunity_candidate_records(store_path=store_path, strict=strict)
    latest_by_id: Dict[str, OpportunityCandidateStoreRecord] = {}
    for record in records:
        latest_by_id[record.opportunity_candidate_id] = record
    return latest_by_id


def index_latest_opportunity_candidates_by_scanner_run(
    *,
    store_path: Any,
    strict: bool = True,
) -> Dict[str, List[OpportunityCandidateStoreRecord]]:
    records = read_opportunity_candidate_records(store_path=store_path, strict=strict)
    indexed: Dict[str, List[OpportunityCandidateStoreRecord]] = {}
    for record in records:
        indexed.setdefault(record.scanner_run_id, []).append(record)
    return indexed


def scan_opportunity_candidate_store(
    *,
    store_path: Any,
) -> OpportunityCandidateStoreScan:
    normalized_path = _normalize_path(store_path)
    if not normalized_path.exists():
        return OpportunityCandidateStoreScan(
            store_path=str(normalized_path),
            row_count=0,
            valid_row_count=0,
            invalid_row_count=0,
            latest_opportunity_candidate_id=None,
            latest_scanner_run_id=None,
            issues=[],
        )

    row_count = 0
    valid_row_count = 0
    invalid_row_count = 0
    latest_opportunity_candidate_id: Optional[str] = None
    latest_scanner_run_id: Optional[str] = None
    issues: List[str] = []

    with normalized_path.open("r", encoding="utf-8") as handle:
        for line_number, raw_line in enumerate(handle, start=1):
            line = raw_line.strip()
            if not line:
                continue
            row_count += 1

            try:
                payload = json.loads(line)
                record = OpportunityCandidateStoreRecord.from_dict(payload)
            except Exception as exc:
                invalid_row_count += 1
                issues.append(f"line {line_number}: {exc}")
                continue

            valid_row_count += 1
            latest_opportunity_candidate_id = record.opportunity_candidate_id
            latest_scanner_run_id = record.scanner_run_id

    return OpportunityCandidateStoreScan(
        store_path=str(normalized_path),
        row_count=row_count,
        valid_row_count=valid_row_count,
        invalid_row_count=invalid_row_count,
        latest_opportunity_candidate_id=latest_opportunity_candidate_id,
        latest_scanner_run_id=latest_scanner_run_id,
        issues=issues,
    )
